// filepath: d:\VSCODE\real time project\CinemaOne\frontend\src\components\ExclusiveContent.js
import React, { useState, useRef, useEffect } from 'react';
import './ExclusiveContent.css';
import {
  FaPlayCircle,
  FaStar,
  FaHeart,
  FaChevronLeft,
  FaChevronRight,
  FaRegHeart,
  FaRegClock,
  FaShareAlt,
  FaCheckCircle,
} from 'react-icons/fa';

const ExclusiveContent = ({ content }) => {
  const [favorites, setFavorites] = useState([]);
  const [current, setCurrent] = useState(0);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');
  const [autoPlay, setAutoPlay] = useState(true);
  const carouselRef = useRef(null);
  const autoPlayRef = useRef();

  // Keyboard navigation for accessibility
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'ArrowLeft') handlePrev();
      if (e.key === 'ArrowRight') handleNext();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
    // eslint-disable-next-line
  }, [current, content.length]);

  // Auto-play carousel
  useEffect(() => {
    autoPlayRef.current = handleNext;
  });

  useEffect(() => {
    if (!autoPlay) return;
    const interval = setInterval(() => {
      autoPlayRef.current();
    }, 5000);
    return () => clearInterval(interval);
  }, [autoPlay, current, content.length]);

  const showUserToast = (msg) => {
    setToastMsg(msg);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 1800);
  };

  const toggleFavorite = (id) => {
    setFavorites((prev) =>
      prev.includes(id) ? prev.filter((fid) => fid !== id) : [...prev, id]
    );
    showUserToast(
      favorites.includes(id)
        ? 'Removed from favorites'
        : 'Added to favorites'
    );
  };

  const handlePrev = () => {
    setCurrent((prev) => (prev === 0 ? content.length - 1 : prev - 1));
    carouselRef.current?.classList.add('carousel-animate-left');
    setTimeout(() => {
      carouselRef.current?.classList.remove('carousel-animate-left');
    }, 400);
  };

  const handleNext = () => {
    setCurrent((prev) => (prev === content.length - 1 ? 0 : prev + 1));
    carouselRef.current?.classList.add('carousel-animate-right');
    setTimeout(() => {
      carouselRef.current?.classList.remove('carousel-animate-right');
    }, 400);
  };

  // Progress bar for carousel
  const progress = ((current + 1) / content.length) * 100;

  // Share functionality
  const handleShare = (item) => {
    if (navigator.share) {
      navigator
        .share({
          title: item.title,
          text: item.description,
          url: item.url,
        })
        .then(() => showUserToast('Shared!'))
        .catch(() => showUserToast('Share cancelled'));
    } else {
      navigator.clipboard.writeText(item.url);
      showUserToast('Link copied!');
    }
  };

  // Pause autoplay on hover
  const handleMouseEnter = () => setAutoPlay(false);
  const handleMouseLeave = () => setAutoPlay(true);

  return (
    <section className="exclusive-content-section">
      <div className="exclusive-header">
        <h2>
          <FaStar className="exclusive-star" /> Exclusive Content
        </h2>
        <p className="exclusive-subtitle">
          Handpicked just for you. Enjoy premium movies and shows!
        </p>
      </div>

      <div
        className="exclusive-carousel-container"
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
      >
        <div className="carousel-progress-bar" aria-label="Carousel progress">
          <div className="carousel-progress" style={{ width: `${progress}%` }} />
        </div>
        <div className="exclusive-carousel" ref={carouselRef}>
          <button
            className="carousel-arrow left"
            onClick={handlePrev}
            aria-label="Previous"
            tabIndex={0}
          >
            <FaChevronLeft />
          </button>
          <div className="exclusive-card featured" key={content[current].id}>
            <div className="exclusive-image-wrapper">
              <img
                src={content[current].image || '/placeholder.jpg'}
                alt={content[current].title}
                className="exclusive-image"
                loading="lazy"
              />
              <span className="exclusive-badge">Exclusive</span>
              <button
                className={`favorite-btn${favorites.includes(content[current].id) ? ' active' : ''}`}
                onClick={() => toggleFavorite(content[current].id)}
                aria-label={
                  favorites.includes(content[current].id)
                    ? 'Remove from favorites'
                    : 'Add to favorites'
                }
                tabIndex={0}
              >
                {favorites.includes(content[current].id) ? <FaHeart /> : <FaRegHeart />}
              </button>
              <button
                className="share-btn"
                onClick={() => handleShare(content[current])}
                aria-label="Share"
                tabIndex={0}
              >
                <FaShareAlt />
              </button>
            </div>
            <div className="exclusive-card-content">
              <h3 className="exclusive-title">{content[current].title}</h3>
              <div className="exclusive-meta">
                <span>
                  <FaRegClock /> {content[current].duration || '2h 10m'}
                </span>
                <span className="exclusive-rating">
                  <FaStar /> {content[current].rating || '4.5'}
                </span>
              </div>
              <p className="exclusive-description">{content[current].description}</p>
              <a
                href={content[current].url}
                target="_blank"
                rel="noopener noreferrer"
                className="exclusive-watch-btn"
              >
                <FaPlayCircle /> Watch Now
              </a>
            </div>
          </div>
          <button
            className="carousel-arrow right"
            onClick={handleNext}
            aria-label="Next"
            tabIndex={0}
          >
            <FaChevronRight />
          </button>
        </div>
        <div className="carousel-dots">
          {content.map((_, idx) => (
            <button
              key={idx}
              className={`carousel-dot${idx === current ? ' active' : ''}`}
              onClick={() => setCurrent(idx)}
              aria-label={`Go to slide ${idx + 1}`}
              tabIndex={0}
            />
          ))}
        </div>
      </div>

      <div className="exclusive-grid">
        {content.map((item) => (
          <div
            className={`exclusive-card${item.id === content[current].id ? ' active' : ''}`}
            key={item.id}
          >
            <div className="exclusive-image-wrapper">
              <img
                src={item.image || '/placeholder.jpg'}
                alt={item.title}
                className="exclusive-image"
                loading="lazy"
              />
              <span className="exclusive-badge">Exclusive</span>
              <button
                className={`favorite-btn${favorites.includes(item.id) ? ' active' : ''}`}
                onClick={() => toggleFavorite(item.id)}
                aria-label={
                  favorites.includes(item.id)
                    ? 'Remove from favorites'
                    : 'Add to favorites'
                }
                tabIndex={0}
              >
                {favorites.includes(item.id) ? <FaHeart /> : <FaRegHeart />}
              </button>
              <button
                className="share-btn"
                onClick={() => handleShare(item)}
                aria-label="Share"
                tabIndex={0}
              >
                <FaShareAlt />
              </button>
            </div>
            <div className="exclusive-card-content">
              <h3 className="exclusive-title">{item.title}</h3>
              <div className="exclusive-meta">
                <span>
                  <FaRegClock /> {item.duration || '2h 10m'}
                </span>
                <span className="exclusive-rating">
                  <FaStar /> {item.rating || '4.5'}
                </span>
              </div>
              <p className="exclusive-description">{item.description}</p>
              <a
                href={item.url}
                target="_blank"
                rel="noopener noreferrer"
                className="exclusive-watch-btn"
              >
                <FaPlayCircle /> Watch Now
              </a>
            </div>
          </div>
        ))}
      </div>

      {showToast && (
        <div className="exclusive-toast" role="alert">
          <FaCheckCircle className="toast-icon" /> {toastMsg}
        </div>
      )}
    </section>
  );
};

export default ExclusiveContent;
